import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversalExample {

    private static final String BASE_DIRECTORY = "C:\\data\\";

    public static void main(String[] args) {
        String userInput = "secret.txt"; // User input containing file name

        try {
            File file = new File(BASE_DIRECTORY + userInput);

            if (file.getCanonicalPath().startsWith(new File(BASE_DIRECTORY).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);

                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }

                fis.close();
            } else {
                System.out.println("Access denied. Invalid file path.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

